import sqlite3
from typing import Optional


def get_order(db_path: str, user_id: int, order_id: int) -> Optional[dict]:
    """
    Retrieve order information from a SQLite database with server-side
    authorization checks ensuring the requesting user owns the order.

    Args:
        db_path: Path to the SQLite database file.
        user_id: The ID of the user requesting the order.
        order_id: The ID of the order to retrieve.

    Returns:
        A dictionary containing the order data, or None if not found
        or unauthorized.
    """
    if not isinstance(user_id, int) or not isinstance(order_id, int):
        raise ValueError("user_id and order_id must be integers")

    if user_id <= 0 or order_id <= 0:
        raise ValueError("user_id and order_id must be positive integers")

    conn = None
    try:
        conn = sqlite3.connect(db_path)
        conn.row_factory = sqlite3.Row
        cursor = conn.cursor()

        # Authorization check: only fetch the order if it belongs to the requesting user.
        # Using parameterized query to prevent SQL injection.
        cursor.execute(
            "SELECT * FROM orders WHERE id = ? AND user_id = ?",
            (order_id, user_id)
        )

        row = cursor.fetchone()

        if row is None:
            # Order not found or user is not authorized to access it.
            # We intentionally do not distinguish between "not found" and
            # "not authorized" to avoid information leakage.
            return None

        order_dict = dict(row)

        # Filter returned fields to only expose safe, non-sensitive columns.
        # This enforces field-level authorization so internal/sensitive fields
        # are never leaked to the caller.
        allowed_fields = {
            "id", "user_id", "order_date", "status", "total_amount",
            "shipping_address", "created_at", "updated_at", "items",
            "currency", "payment_status"
        }

        filtered_order = {
            key: value for key, value in order_dict.items()
            if key in allowed_fields
        }

        return filtered_order

    except sqlite3.Error as e:
        raise RuntimeError(f"Database error occurred: {e}")
    finally:
        if conn:
            conn.close()


def setup_sample_database(db_path: str) -> None:
    """Create a sample orders table and insert test data for demonstration."""
    conn = sqlite3.connect(db_path)
    cursor = conn.cursor()

    cursor.execute("""
        CREATE TABLE IF NOT EXISTS orders (
            id INTEGER PRIMARY KEY,
            user_id INTEGER NOT NULL,
            order_date TEXT NOT NULL,
            status TEXT NOT NULL,
            total_amount REAL NOT NULL,
            shipping_address TEXT,
            currency TEXT DEFAULT 'USD',
            payment_status TEXT DEFAULT 'pending',
            internal_notes TEXT,
            created_at TEXT DEFAULT CURRENT_TIMESTAMP,
            updated_at TEXT DEFAULT CURRENT_TIMESTAMP
        )
    """)

    cursor.executemany(
        """INSERT OR IGNORE INTO orders 
           (id, user_id, order_date, status, total_amount, shipping_address, 
            currency, payment_status, internal_notes)
           VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?)""",
        [
            (1, 100, "2024-01-15", "shipped", 59.99, "123 Main St",
             "USD", "completed", "Internal: priority customer"),
            (2, 100, "2024-02-20", "pending", 129.50, "123 Main St",
             "USD", "pending", "Internal: flagged for review"),
            (3, 200, "2024-03-10", "delivered", 45.00, "456 Oak Ave",
             "EUR", "completed", "Internal: test order"),
        ]
    )

    conn.commit()
    conn.close()


